// 정규화 공고를 pending으로 bulk INSERT하는 SQL 생성 (within-run 중복 제거 + ON CONFLICT).
const esc = (v) => v == null ? 'NULL' : `'${String(v).replace(/'/g, "''")}'`;
const num = (v) => (v == null || v === '') ? 'NULL' : (Number.isFinite(Number(v)) ? Number(v) : 'NULL');
const arr = (list) => { const a = (list || []).map(s => `'${String(s).replace(/'/g, "''")}'`); return a.length ? `ARRAY[${a.join(',')}]::text[]` : `'{}'::text[]`; };
const seen = new Set();
const rows = [];
for (const it of $input.all()) {
  const m = it.json;
  const key = `${m.source}:${m.jobId}`;
  if (!m.jobId || seen.has(key)) continue;   // 이번 실행 내 중복 제거(bulk insert 중복 target 방지)
  seen.add(key);
  rows.push(`(${esc(m.source)},${esc(m.jobId)},${esc(m.company)},${esc(m.title)},${esc(m.url)},${num(m.minCareer)},${num(m.maxCareer)},${arr(m.techStacks)},${esc((m.locations || []).join(', '))},${m.closedAt ? esc(m.closedAt) : 'NULL'})`);
}
if (rows.length === 0) return [];
const sql = `INSERT INTO jobs (source,job_id,company,title,url,min_career,max_career,tech_stacks,locations,closed_at) VALUES ${rows.join(',')} ON CONFLICT (source,job_id) DO NOTHING;`;
return [{ json: { sql, count: rows.length } }];

// 자동 페이지네이션: 각 키워드/직군을 page 1부터 "빈 결과 나올 때까지" 가져온다.
// (maxPages는 안전 상한으로만 작동. 실제로는 빈 페이지에서 자동 종료.)
// 가져오면서 바로 정규화 + 제목필터 + 연차필터 적용.
const cfg = $('설정 (Config)').first().json;
const keywords = cfg.keywords || [];
const cats = cfg.allowedWantedCategories || [518, 507];
const cap = Math.max(1, Number(cfg.maxPages) || 100);   // 안전 상한(페이지)
const maxYears = Number(cfg.maxCareerYears);
const UA = { 'User-Agent': 'Mozilla/5.0' };

const stripTags = (s) => (s || '').replace(/<[^>]*>/g, '').trim();
const escRe = (s) => s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
const titleHit = (t) => keywords.some(kw => new RegExp('(^|[^A-Za-z0-9])' + escRe(kw) + '([^A-Za-z0-9]|$)', 'i').test(t || ''));
const careerOk = (mc) => !Number.isFinite(maxYears) || mc == null || mc <= maxYears;

const out = [];

// ── 점프잇: 키워드별 page 페이지네이션 ──
for (const kw of keywords) {
  const q = encodeURIComponent(kw);
  for (let page = 1; page <= cap; page++) {
    let r;
    try { r = await this.helpers.httpRequest({ url: `https://jumpit-api.saramin.co.kr/api/positions?keyword=${q}&sort=relation&page=${page}`, headers: UA, json: true }); }
    catch (e) { break; }
    const pos = r?.result?.positions || [];
    if (pos.length === 0) break;                    // 빈 페이지 → 이 키워드 종료
    for (const p of pos) {
      const title = stripTags(p.title);
      const minCareer = p.minCareer ?? null;
      if (!titleHit(title) || !careerOk(minCareer)) continue;
      out.push({ json: { source:'jumpit', jobId:String(p.id ?? ''), company:p.companyName ?? '', title,
        url:`https://jumpit.saramin.co.kr/position/${p.id}`, minCareer, maxCareer:p.maxCareer ?? null,
        techStacks:(p.techStacks||[]).map(t=>stripTags(typeof t==='string'?t:(t.stack??t.name??''))),
        locations:p.locations??[], closedAt:p.closedAt??null } });
    }
  }
}

// ── 원티드: navigation 직군별 offset 페이지네이션 ──
for (const cat of cats) {
  for (let page = 1; page <= cap; page++) {
    const offset = (page - 1) * 20;
    let r;
    try { r = await this.helpers.httpRequest({ url: `https://www.wanted.co.kr/api/chaos/navigation/v1/results?job_group_id=${cat}&country=kr&job_sort=job.latest_order&locations=all&years=-1&limit=20&offset=${offset}`, headers: UA, json: true }); }
    catch (e) { break; }
    const data = r?.data || [];
    if (data.length === 0) break;                   // 빈 결과 → 이 직군 종료
    for (const p of data) {
      const pid = p.category_tag?.parent_id;
      if (cats.length && pid != null && !cats.includes(pid)) continue;
      const title = p.position ?? '';
      const minCareer = p.annual_from ?? null;
      let maxCareer = p.annual_to ?? null;
      if (maxCareer != null && maxCareer > 20) maxCareer = null;
      if (!titleHit(title) || !careerOk(minCareer)) continue;
      out.push({ json: { source:'wanted', jobId:String(p.id ?? ''), company:p.company?.name ?? '', title,
        url:`https://www.wanted.co.kr/wd/${p.id}`, minCareer, maxCareer,
        techStacks:(p.skill_tags||[]).map(t=>stripTags(typeof t==='string'?t:(t.title??t.name??''))),
        locations:(p.address?[[p.address.location,p.address.district].filter(Boolean).join(' ')].filter(Boolean):[]), closedAt:p.due_time??null } });
    }
  }
}

return out;
